class Playground {
  async run(inputs) {
    const nums = inputs[0].split(',').map(x => parseInt(x.trim()));
    this.array.init(nums);
    this.log('Check if array contains any duplicate values');
    await this.await();

    this.log('Strategy: Use HashMap to track seen numbers');
    await this.await();

    for (let i = 0; i < nums.length; i++) {
      const num = nums[i];
      this.ptr.set('i', i);
      this.array.highlight(i, '#3b82f6');
      this.log(`Index ${i}: checking value ${num}`);
      await this.await();

      if (this.hashmap.has(num)) {
        const prevIdx = this.hashmap.get(num);
        this.hashmap.highlight(num, '#ef4444');
        this.log(`🔍 Found ${num} in hashmap at index ${prevIdx}`);
        await this.await();

        this.array.highlight(prevIdx, '#ef4444');
        this.array.highlight(i, '#ef4444');
        this.log(`✅ Duplicate found! ${num} appears at indices ${prevIdx} and ${i}`);
        await this.await();

        this.ptr.remove('i');
        return true;
      }

      this.hashmap.put(num, i);
      this.array.highlight(i, '#10b981');
      this.log(`First occurrence: stored hashmap[${num}] = ${i}`);
      await this.await();

      this.array.clearHighlights();
    }

    this.ptr.remove('i');
    this.log('❌ No duplicates found - all values unique');
    await this.await();
    return false;
  }
}
